lower = 牢獄Ｂ２
level = 44
bgm = bad
margin = 1
roof = stone
shadow = dark
sky = black
outfield = soil
blank = rock
antiWarp = true

; パーツ画像
━ = stone
　 = marble
／ = door
〆 = key
☗ = gate
︻ = panel
┯ = button
⑹ = box
⑺ = box
⑻ = box
⑼ = box

; 敵情報
maxGroups = 2
monsters = ウインターコボルド

; 移動ポイント
(A) = map:フーラ雪原・南の森, x:14, y:13, way:s, symbol:exit ,ask:Leave the dungeon?

; 宝箱
box[1] = 罠はない,学びのメダル

