;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 3, 4]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@command title="Which button will you press?" cancel=true
@select text="Ｂ２" exp='tf.result = ["牢獄Ｂ２", "down"]'
@select text="Ｂ３" exp='tf.result = ["牢獄Ｂ３", "down"]'
@select text="Ｂ４" exp='tf.result = ["牢獄Ｂ４", "down"]'
@select text="No" exp='tf.result = []'
[ask]
@elevator map=&'tf.result[0]' lift=&'tf.result[1]' cond='tf.result.count > 0'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@delevent
@jump storage="main10.scn" target=*jail_01

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text=Guardhouse

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] f.partyPrisonerNums.count == 0

@wait time=500
@fg c=devil_yellow left=450 top=-15
[texton]
[name n="Chief Guard"]「How the hell did you guys escape from jail?」[k]
[name n="Chief Guard"]「Damn it, if it comes to this, I'll finish you all off right here!」[k]
[textoff]
@clf
@monster pos=3 name=レッサーデビル
@callbattle bgm=boss gameover=true escape=false
@delevent
@treasure item=看守の鍵

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] true

@delevent
@jump storage="main10.scn" target=*jail_05 cond='game.isFreeMode || game.waitingMembers.count > 0'

[eventoff]
;-------------------------------------------------------------------------------
